import{_ as e,o as s,c as n,ai as i}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"Linux App","description":"","frontmatter":{"summary":"Linux support + companion app status","read_when":["Looking for Linux companion app status","Planning platform coverage or contributions"],"title":"Linux App"},"headers":[],"relativePath":"platforms/linux.md","filePath":"platforms/linux.md","lastUpdated":1771906665000}'),l={name:"platforms/linux.md"};function t(p,a,r,o,d,c){return s(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="linux-app" tabindex="-1"><a class="header-anchor" href="#linux-app">#</a> Linux App</h1><p>The Gateway is fully supported on Linux. <strong>Node is the recommended runtime</strong>. Bun is not recommended for the Gateway (WhatsApp/Telegram bugs).</p><p>Native Linux companion apps are planned. Contributions are welcome if you want to help build one.</p><h2 id="beginner-quick-path-vps" tabindex="-1"><a class="header-anchor" href="#beginner-quick-path-vps">#</a> Beginner quick path (VPS)</h2><ol><li>Install Node 22+</li><li><code>npm i -g opensoul@latest</code></li><li><code>opensoul onboard --install-daemon</code></li><li>From your laptop: <code>ssh -N -L 18789:127.0.0.1:18789 &lt;user&gt;@&lt;host&gt;</code></li><li>Open <code>http://127.0.0.1:18789/</code> and paste your token</li></ol><p>Step-by-step VPS guide: <a href="/docs/install/exe-dev">exe.dev</a></p><h2 id="install" tabindex="-1"><a class="header-anchor" href="#install">#</a> Install</h2><ul><li><a href="/docs/start/getting-started">Getting Started</a></li><li><a href="/docs/install/updating">Install &amp; updates</a></li><li>Optional flows: <a href="/docs/install/bun">Bun (experimental)</a>, <a href="/docs/install/nix">Nix</a>, <a href="/docs/install/docker">Docker</a></li></ul><h2 id="gateway" tabindex="-1"><a class="header-anchor" href="#gateway">#</a> Gateway</h2><ul><li><a href="/docs/gateway/index">Gateway runbook</a></li><li><a href="/docs/gateway/configuration">Configuration</a></li></ul><h2 id="gateway-service-install-cli" tabindex="-1"><a class="header-anchor" href="#gateway-service-install-cli">#</a> Gateway service install (CLI)</h2><p>Use one of these:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensoul onboard --install-daemon</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Or:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensoul gateway install</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Or:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensoul configure</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Select <strong>Gateway service</strong> when prompted.</p><p>Repair/migrate:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensoul doctor</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="system-control-systemd-user-unit" tabindex="-1"><a class="header-anchor" href="#system-control-systemd-user-unit">#</a> System control (systemd user unit)</h2><p>OpenSoul installs a systemd <strong>user</strong> service by default. Use a <strong>system</strong> service for shared or always-on servers. The full unit example and guidance live in the <a href="/docs/gateway/index">Gateway runbook</a>.</p><p>Minimal setup:</p><p>Create <code>~/.config/systemd/user/opensoul-gateway[-&lt;profile&gt;].service</code>:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Unit]</span></span>
<span class="line"><span>Description=OpenSoul Gateway (profile: &lt;profile&gt;, v&lt;version&gt;)</span></span>
<span class="line"><span>After=network-online.target</span></span>
<span class="line"><span>Wants=network-online.target</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Service]</span></span>
<span class="line"><span>ExecStart=/usr/local/bin/opensoul gateway --port 18789</span></span>
<span class="line"><span>Restart=always</span></span>
<span class="line"><span>RestartSec=5</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[Install]</span></span>
<span class="line"><span>WantedBy=default.target</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>Enable it:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>systemctl --user enable --now opensoul-gateway[-&lt;profile&gt;].service</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div>`,27)])])}const b=e(l,[["render",t]]);export{h as __pageData,b as default};
